import { HorizontalStepperRoot, type HorizontalStepperProps } from "./horizontal-stepper";
import { HorizontalStepperStep, type HorizontalStepperStepProps } from "./horizontal-stepper-step";

const HorizontalStepper = Object.assign(HorizontalStepperRoot, {
  Step: HorizontalStepperStep,
});

export { HorizontalStepper, type HorizontalStepperProps };
export { HorizontalStepperStep, type HorizontalStepperStepProps };
export { stepVariants } from "./horizontal-stepper-step";
export { useStepInfo, type StepStatus } from "./horizontal-stepper-context";

"use client";

import { useMemo, type ReactNode } from "react";
import { cn } from "@/lib/utils";
import { HorizontalStepperContext } from "./horizontal-stepper-context";

export interface HorizontalStepperProps {
  steps: string[];
  step: string;
  children: ReactNode;
  className?: string;
  "aria-label"?: string;
}

export function HorizontalStepperRoot({
  steps,
  step,
  children,
  className,
  "aria-label": ariaLabel,
}: HorizontalStepperProps) {
  const contextValue = useMemo(() => ({ step, steps }), [step, steps]);

  return (
    <HorizontalStepperContext value={contextValue}>
      <ol
        aria-label={ariaLabel ?? "Progress"}
        className={cn("flex items-center gap-1 font-mono text-[10px]", className)}
      >
        {children}
      </ol>
    </HorizontalStepperContext>
  );
}

"use client";

import { createContext, useContext } from "react";
import type { StepStatus } from "@/lib/step-status";

export type { StepStatus };

interface StepperContextValue {
  step: string;
  steps: string[];
}

export const HorizontalStepperContext = createContext<StepperContextValue | undefined>(undefined);

export function useStepperContext() {
  const ctx = useContext(HorizontalStepperContext);
  if (ctx === undefined) {
    throw new Error("HorizontalStepperStep must be used within a HorizontalStepper");
  }
  return ctx;
}

export function useStepInfo(value: string): { status: StepStatus; index: number } {
  const { step, steps } = useStepperContext();
  const stepIndex = steps.indexOf(value);
  const currentIndex = steps.indexOf(step);

  if (stepIndex === currentIndex) return { status: "active", index: stepIndex };
  if (stepIndex < currentIndex) return { status: "completed", index: stepIndex };
  return { status: "pending", index: stepIndex };
}

"use client";

import type { ReactNode } from "react";
import { cva } from "class-variance-authority";
import { cn } from "@/lib/utils";
import { useStepInfo, type StepStatus } from "./horizontal-stepper-context";

export const stepVariants = cva("px-1.5 py-0.5", {
  variants: {
    status: {
      active: "bg-foreground text-primary-foreground font-bold",
      completed: "text-success",
      pending: "text-muted-foreground",
      error: "text-error-fg font-bold",
    },
  },
  defaultVariants: { status: "pending" },
});

const srLabel: Record<StepStatus, string> = {
  completed: "Completed: ",
  active: "Current: ",
  pending: "Upcoming: ",
  error: "Error: ",
};

export interface HorizontalStepperStepProps {
  value: string;
  children: ReactNode;
  className?: string;
}

export function HorizontalStepperStep({ value, children, className }: HorizontalStepperStepProps) {
  const { status, index } = useStepInfo(value);

  return (
    <li aria-current={status === "active" ? "step" : undefined} className="flex items-center gap-1">
      {index > 0 && (
        <span aria-hidden="true" className={cn("mx-0.5", status === "completed" ? "text-success" : "text-border")}>
          -
        </span>
      )}
      <span className={cn(stepVariants({ status }), className)}>
        <span className="sr-only">{srLabel[status]}</span>
        {children}
      </span>
    </li>
  );
}
